// Application State
// ==========================================================================
let currentFilter = 'all';
let searchQuery = '';
let favorites = JSON.parse(localStorage.getItem('mvz_favorites')) || [];
let toastTimeout = null;

// ==========================================================================
// DOM Elements
// ==========================================================================
const promptGrid = document.getElementById('promptGrid');
const searchInput = document.getElementById('searchInput');
const clearSearchBtn = document.getElementById('clearSearch');
const filterChips = document.querySelectorAll('.filter-chip');
const emptyState = document.getElementById('emptyState');
const resetFiltersBtn = document.getElementById('resetFilters');
const copyToast = document.getElementById('copyToast');


// ==========================================================================
// Core Render Functionality
// ==========================================================================
function renderCards() {
    promptGrid.innerHTML = '';
    
    let filteredPrompts = [];
    
    if (currentFilter === 'all') {
        // Show ALL prompts mixed: truly interleave videos and images
        const isVideo = p => p.videoUrl && p.videoUrl.endsWith('.mp4');
        const videos = promptsData.filter(p => isVideo(p));
        const images = promptsData.filter(p => !isVideo(p));
        const mixed = [];
        let vi = 0, ii = 0;
        while (vi < videos.length || ii < images.length) {
            if (vi < videos.length) mixed.push(videos[vi++]);
            if (ii < images.length) mixed.push(images[ii++]);
        }
        filteredPrompts = mixed;
    } else if (currentFilter === 'favorites') {
        filteredPrompts = promptsData.filter(prompt => favorites.includes(prompt.id));
    } else if (currentFilter === 'ritmico') {
        // Show ONLY prompts with the YouTube Create badge
        filteredPrompts = promptsData.filter(prompt => prompt.youtubeCreate);
    } else if (currentFilter === 'animacoes') {
        // Show ONLY prompts that have video (.mp4) - excluding YouTube Create
        filteredPrompts = promptsData.filter(prompt => prompt.videoUrl && prompt.videoUrl.endsWith('.mp4') && !prompt.youtubeCreate);
    } else if (currentFilter === 'imagens') {
        // Show ONLY prompts that have images (NOT .mp4 videos)
        filteredPrompts = promptsData.filter(prompt => prompt.videoUrl && !prompt.videoUrl.endsWith('.mp4'));
    }
    
    // Apply Search filter
    if (searchQuery.trim() !== '') {
        const query = searchQuery.toLowerCase();
        filteredPrompts = filteredPrompts.filter(prompt => {
            const matchesTitle = prompt.title.toLowerCase().includes(query);
            const matchesDesc = prompt.desc.toLowerCase().includes(query);
            const matchesPrompt = prompt.promptText.toLowerCase().includes(query);
            return matchesTitle || matchesDesc || matchesPrompt;
        });
    }

    if (filteredPrompts.length === 0) {
        promptGrid.style.display = 'none';
        emptyState.style.display = 'flex';
        return;
    }

    promptGrid.style.display = 'grid';
    emptyState.style.display = 'none';

    filteredPrompts.forEach(prompt => {
        const isFavorited = favorites.includes(prompt.id);
        const hasVideo = prompt.videoUrl && prompt.videoUrl.toLowerCase().endsWith('.mp4');
        const cardHTML = `
            <div class="prompt-card" data-id="${prompt.id}">
                <!-- YouTube Create Badge -->
                ${prompt.youtubeCreate ? `
                <div class="ytb-badge">
                    <i data-lucide="youtube" class="ytb-icon"></i>
                    <span>YTB</span>
                </div>` : ''}
                
                <!-- Favorite Heart Button -->
                <button class="favorite-btn ${isFavorited ? 'favorited' : ''}" aria-label="Favoritar prompt" onclick="toggleFavorite(event, '${prompt.id}')">
                    <i data-lucide="heart"></i>
                </button>
                
                <!-- Video / Thumbnail Media Container -->
                <div class="card-media-container">
                    <img src="${prompt.thumbnailUrl}" alt="${prompt.title}" class="card-thumbnail">
                    ${hasVideo ? `
                    <video class="card-video" loop muted playsinline preload="none">
                        <source src="${prompt.videoUrl}" type="video/mp4">
                    </video>` : ''}
                </div>
                
                <div class="card-overlay"></div>
                
                <!-- Info Overlay Details -->
                <div class="card-content">
                    <h3 class="card-title">${prompt.title}</h3>
                    <p class="card-desc">${prompt.desc}</p>
                    <button class="btn-copy-prompt" onclick="copyPromptText(event, \`${escapePromptString(prompt.promptText)}\`)">
                        <i data-lucide="copy"></i>
                        <span>Copiar Prompt</span>
                    </button>
                </div>
            </div>
        `;
        promptGrid.insertAdjacentHTML('beforeend', cardHTML);
    });

    // Reinitialize Lucide Icons for dynamically generated elements
    lucide.createIcons();
    setupVideoHoverListeners();
}

// Helper: Translate category string to portuguese badge text
function getFriendlyCategoryName(category) {
    const categories = {
        'selfie': 'Imagens',
        'ritmico': 'YouTube Create',
        'apresentacao': 'Flow',
        'transicao': 'Transição',
        'destaque': 'Grok'
    };
    return categories[category] || category;
}

// Helper: Escape backticks and double quotes for safe inline inline function params
function escapePromptString(str) {
    return str.replace(/"/g, '&quot;').replace(/`/g, '\\`');
}

// ==========================================================================
// Interactive Event Listeners (Video Playbacks on Hover)
// ==========================================================================
function setupVideoHoverListeners() {
    const cards = document.querySelectorAll('.prompt-card');
    
    cards.forEach(card => {
        const video = card.querySelector('.card-video');
        const thumbnail = card.querySelector('.card-thumbnail');
        
        let playPromise = null;
        
        card.addEventListener('mouseenter', () => {
            if (video) {
                // Preload video on hover if not already preloaded
                if (video.readyState === 0) {
                    video.load();
                }
                
                // Fade out thumbnail slightly, play video
                playPromise = video.play();
                
                if (playPromise !== undefined) {
                    playPromise.then(() => {
                        thumbnail.style.opacity = '0';
                    }).catch(error => {
                        console.warn("Video play interrupted/failed:", error);
                    });
                }
            }
        });
        
        card.addEventListener('mouseleave', () => {
            if (video) {
                if (playPromise !== undefined) {
                    playPromise.then(() => {
                        video.pause();
                        video.currentTime = 0; // Rewind video to start on leave
                        thumbnail.style.opacity = '1';
                    }).catch(() => {
                        video.pause();
                        video.currentTime = 0;
                        thumbnail.style.opacity = '1';
                    });
                } else {
                    video.pause();
                    video.currentTime = 0;
                    thumbnail.style.opacity = '1';
                }
            }
        });
    });
}

// ==========================================================================
// Copy to Clipboard Action
// ==========================================================================
function copyPromptText(event, text) {
    event.stopPropagation(); // Avoid triggering card clicking events if any
    
    navigator.clipboard.writeText(text).then(() => {
        showToastNotification();
    }).catch(err => {
        console.error('Falha ao copiar prompt: ', err);
    });
}

function showToastNotification() {
    if (toastTimeout) {
        clearTimeout(toastTimeout);
        copyToast.classList.remove('show');
        // Small delay to trigger animation reset
        setTimeout(() => {
            triggerToastShow();
        }, 50);
    } else {
        triggerToastShow();
    }
}

function triggerToastShow() {
    copyToast.classList.add('show');
    
    // Set duration custom variable for animation sync
    copyToast.style.setProperty('--duration', '3s');
    
    toastTimeout = setTimeout(() => {
        copyToast.classList.remove('show');
        toastTimeout = null;
    }, 3000);
}

// ==========================================================================
// Favorites Management (Local Storage Sync)
// ==========================================================================
window.toggleFavorite = function(event, promptId) {
    event.stopPropagation();
    const btn = event.currentTarget;
    
    if (favorites.includes(promptId)) {
        favorites = favorites.filter(id => id !== promptId);
        btn.classList.remove('favorited');
    } else {
        favorites.push(promptId);
        btn.classList.add('favorited');
    }
    
    localStorage.setItem('mvz_favorites', JSON.stringify(favorites));
    
    // If we are currently in favorites tab, filter out immediately
    if (currentFilter === 'favorites') {
        renderCards();
    } else {
        // Toggle icon color/fill dynamically without full re-render
        const icon = btn.querySelector('i');
        if (favorites.includes(promptId)) {
            icon.setAttribute('fill', 'currentColor');
            lucide.createIcons();
        } else {
            icon.removeAttribute('fill');
            lucide.createIcons();
        }
    }
};

// ==========================================================================
// Input / Searching and Categorization Filtering
// ==========================================================================
searchInput.addEventListener('input', (e) => {
    searchQuery = e.target.value;
    
    if (searchQuery.trim() !== '') {
        clearSearchBtn.style.display = 'flex';
    } else {
        clearSearchBtn.style.display = 'none';
    }
    
    renderCards();
});

clearSearchBtn.addEventListener('click', () => {
    searchInput.value = '';
    searchQuery = '';
    clearSearchBtn.style.display = 'none';
    renderCards();
});

filterChips.forEach(chip => {
    chip.addEventListener('click', () => {
        filterChips.forEach(c => c.classList.remove('active'));
        chip.classList.add('active');
        
        currentFilter = chip.getAttribute('data-category');
        renderCards();
    });
});

resetFiltersBtn.addEventListener('click', () => {
    searchInput.value = '';
    searchQuery = '';
    clearSearchBtn.style.display = 'none';
    
    filterChips.forEach(c => c.classList.remove('active'));
    document.querySelector('.filter-chip[data-category="all"]').classList.add('active');
    
    currentFilter = 'all';
    renderCards();
});


// ==========================================================================
// Page Initialization
// ==========================================================================
document.addEventListener('DOMContentLoaded', () => {
    lucide.createIcons();
    renderCards();
});
